import { Component, OnInit, AfterViewInit } from '@angular/core';
import { ResultatService } from '../../services/resultat.service';

declare var Chart: any;

@Component({
  selector: 'app-estadistiques',
  templateUrl: './estadistiques.component.html'
})
export class EstadistiquesComponent implements OnInit, AfterViewInit {
  stats: any = null;
  loading = true;
  error = '';
  private chartsReady = false;
  private statsReady = false;

  constructor(private resultatService: ResultatService) {}

  ngOnInit(): void {
    this.resultatService.getMevesEstadistiques().subscribe({
      next: (s) => {
        this.stats = s;
        this.loading = false;
        this.statsReady = true;
        if (this.chartsReady) this.renderCharts();
      },
      error: () => {
        this.error = 'No s\'han pogut carregar les estadístiques.';
        this.loading = false;
      }
    });
  }

  ngAfterViewInit(): void {
    const script = document.createElement('script');
    script.src = 'https://cdn.jsdelivr.net/npm/chart.js@4.4.0/dist/chart.umd.min.js';
    script.onload = () => {
      this.chartsReady = true;
      if (this.statsReady) this.renderCharts();
    };
    document.head.appendChild(script);
  }

  renderCharts(): void {
    if (!this.stats) return;

    // Gràfic de pastís: victòries / derrotes
    const ctxDoughnut = document.getElementById('chartVD') as HTMLCanvasElement;
    if (ctxDoughnut) {
      new Chart(ctxDoughnut, {
        type: 'doughnut',
        data: {
          labels: ['Victòries', 'Derrotes'],
          datasets: [{
            data: [this.stats.victories, this.stats.derrotes],
            backgroundColor: ['#198754', '#dc3545']
          }]
        },
        options: { responsive: true, plugins: { legend: { position: 'bottom' } } }
      });
    }

    // Gràfic de barres: combats totals simulat per mesos (demo)
    const ctxBar = document.getElementById('chartMesos') as HTMLCanvasElement;
    if (ctxBar) {
      new Chart(ctxBar, {
        type: 'bar',
        data: {
          labels: ['Gen', 'Feb', 'Mar', 'Abr', 'Mai', 'Jun'],
          datasets: [{
            label: 'Combats',
            data: [1, 3, 2, 4, 2, this.stats.totalCombats],
            backgroundColor: '#0d6efd'
          }]
        },
        options: { responsive: true, plugins: { legend: { display: false } } }
      });
    }

    // Gràfic de línies: evolució del rendiment (demo)
    const ctxLine = document.getElementById('chartEvolucio') as HTMLCanvasElement;
    if (ctxLine) {
      new Chart(ctxLine, {
        type: 'line',
        data: {
          labels: ['Gen', 'Feb', 'Mar', 'Abr', 'Mai', 'Jun'],
          datasets: [{
            label: '% Victòries',
            data: [40, 50, 45, 60, 55, this.stats.percentatgeVictories],
            borderColor: '#198754',
            backgroundColor: 'rgba(25,135,84,0.1)',
            fill: true,
            tension: 0.3
          }]
        },
        options: { responsive: true, scales: { y: { min: 0, max: 100 } } }
      });
    }
  }
}
<h4 class="mb-4"><i class="bi bi-bar-chart-fill me-2"></i>Les meves estadístiques</h4>

<div class="alert alert-danger" *ngIf="error">{{ error }}</div>

<div class="text-center py-5" *ngIf="loading">
  <div class="spinner-border"></div>
</div>

<div *ngIf="!loading && stats">
  <!-- Targetes resum -->
  <div class="row g-3 mb-4">
    <div class="col-6 col-md-3">
      <div class="card text-center p-3">
        <div class="fs-2 fw-bold text-primary">{{ stats.totalCombats }}</div>
        <div class="text-muted small">Total combats</div>
      </div>
    </div>
    <div class="col-6 col-md-3">
      <div class="card text-center p-3">
        <div class="fs-2 fw-bold text-success">{{ stats.victories }}</div>
        <div class="text-muted small">Victòries</div>
      </div>
    </div>
    <div class="col-6 col-md-3">
      <div class="card text-center p-3">
        <div class="fs-2 fw-bold text-danger">{{ stats.derrotes }}</div>
        <div class="text-muted small">Derrotes</div>
      </div>
    </div>
    <div class="col-6 col-md-3">
      <div class="card text-center p-3">
        <div class="fs-2 fw-bold text-warning">{{ stats.percentatgeVictories }}%</div>
        <div class="text-muted small">% Victòries</div>
      </div>
    </div>
  </div>

  <!-- Gràfics -->
  <div class="row g-3">
    <div class="col-md-4">
      <div class="card p-3">
        <h6 class="text-muted mb-3">Victòries / Derrotes</h6>
        <canvas id="chartVD"></canvas>
      </div>
    </div>
    <div class="col-md-4">
      <div class="card p-3">
        <h6 class="text-muted mb-3">Combats per mes</h6>
        <canvas id="chartMesos"></canvas>
      </div>
    </div>
    <div class="col-md-4">
      <div class="card p-3">
        <h6 class="text-muted mb-3">Evolució del rendiment</h6>
        <canvas id="chartEvolucio"></canvas>
      </div>
    </div>
  </div>
</div>
